+        KillOnDropReapStrategy::BlockingPool => {
+            if let Some(pool) = blocking_pool_for_kill_on_drop_reap() {
+                match try_dispatch_kill_on_drop_reap_on_pool(&pool, child) {
+                    Ok(()) => return,
+                    Err(recovered_child) => {
+                        child = recovered_child;
