+                    Err(mut recovered_child) => {
+                        let _ = recovered_child.wait();
+                    }
+                }
+            } else {
+                let _ = child.wait();
+            }
+        }
+        KillOnDropReapStrategy::DetachedThread => match spawn_detached_kill_on_drop_reaper(child) {
